export async function seed(knex: Knex): Promise<void> {
  await knex('startup_terminologies').del();

  const grouped: Record<string, any[]> = {};

  for (const item of termsData) {
    const { category, term, icon, definition, example } = item;

    if (!grouped[category]) {
      grouped[category] = [];
    }

    grouped[category].push({
      name: term,
      icon,
      definition,
      example,
    });
  }

  const rows = Object.entries(grouped).map(([category, data]) => ({
    category,
    data: JSON.stringify(data),
  }));

  await knex('startup_terminologies').insert(rows);
}
